// Reads the app's barometer config (roles + geography), runs an Apify job-board
// scraper actor per role (LinkedIn / Indeed / etc. — the actors handle anti-bot,
// not you), counts returned postings, then POSTs one generalized barometer point.
//
// IMPORTANT — a RELATIVE INDEX, not a true total. Fix the method: same actor,
// same maxItems, same query shape every month. The app turns the proxy count into
// an index (base 100), comparable month-to-month. Raw count + source shown in the
// app's tooltip so the number is never mistaken for a precise total.
//
// Requires: APIFY_TOKEN, and APIFY_ACTOR (e.g. a LinkedIn Jobs Scraper actor id,
// like 'bebity~linkedin-jobs-scraper' — pick one you trust on apify.com and adapt
// the `input` shape to that actor's schema). Set KIST_URL to your app.
const KIST = $env.KIST_URL || 'http://127.0.0.1:8321';
const TOKEN = $env.APIFY_TOKEN;
const ACTOR = $env.APIFY_ACTOR; // e.g. 'bebity~linkedin-jobs-scraper'
const MAX = 200; // fixed cap — DO NOT change between months (breaks comparability)

const cfg = await this.helpers.httpRequest({ url: `${KIST}/api/market-barometer`, json: true });
const roles = cfg.roles || [];
const geo = (cfg.geo || []).join(', ') || 'Remote';

const counts = {};
for (const r of roles) {
  // run-sync-get-dataset-items returns the actor's scraped items directly
  const items = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.apify.com/v2/acts/${ACTOR}/run-sync-get-dataset-items?token=${TOKEN}`,
    body: { title: r.query || r.label, location: geo, rows: MAX, maxItems: MAX },
    json: true,
  });
  counts[r.key] = Array.isArray(items) ? items.length : 0;
}

const month = new Date().toISOString().slice(0, 7);
return [{ json: {
  month, counts,
  sources: `Apify ${ACTOR} (max ${MAX})`,
  geo, as_of: new Date().toISOString().slice(0, 10),
} }];
